const item = $input.first();
const headers = item.json.headers || {};
const body = item.json.body || {};

const expected = $env.SERVICE_WEBHOOK_SECRET || '';
const got = headers['x-service-webhook-secret'] || '';
if (expected && got !== expected) {
  throw new Error('Invalid X-Service-Webhook-Secret');
}

const t = body.task || {};
const taskId = t.id || body.taskId || '';
if (!taskId) { throw new Error('No task.id in service webhook payload'); }

return [{ json: {
  eventType: body.eventType || '',
  taskId: taskId,
  name: t.name || '(untitled task)',
  status: t.status || '',
  previousStatus: t.previousStatus || '',
  priority: t.urgency || t.priority || 'Normal',
  assignedUserId: t.assignedUserId || '',
  assignedUserName: t.assignedUserName || '',
  dateDue: t.dateDue || t.slaDueDate || '',
  parentType: t.parentType || '',
  parentName: t.parentName || '',
  accountName: t.accountName || '',
  contactName: t.contactName || '',
  taskType: t.taskType || ''
} }];

const ev = $('Validate & Parse Service Event').first().json;
const lk = $input.first() ? ($input.first().json || {}) : {};
const slackUserId = lk.slack_user_id || null;
const fallback = $env.TASK_NOTIFY_FALLBACK_CHANNEL || 'C0AUP125PRU';
const channel = slackUserId || fallback;

const metaMap = {
  'service.task_started': { emoji: '🔵', title: 'Task In Progress' },
  'service.request_to_client': { emoji: '⏳', title: 'Waiting on Client' },
  'service.task_completed': { emoji: '✅', title: 'Task Completed' }
};
const meta = metaMap[ev.eventType] || { emoji: '📋', title: 'Task Update' };
const prMap = { Urgent: '🔴', High: '🟠', Normal: '🟡', Low: '⚪' };
const pe = prMap[ev.priority] || '🟡';

let due = '_Not set_';
if (ev.dateDue) {
  const ms = Date.parse(ev.dateDue.length <= 10 ? ev.dateDue + 'T00:00:00Z' : ev.dateDue);
  due = isNaN(ms) ? ev.dateDue : ('<!date^' + Math.floor(ms/1000) + '^{date_short}|' + ev.dateDue + '>');
}
const related = ev.accountName || ev.contactName || (ev.parentName ? (ev.parentType + ': ' + ev.parentName) : '_None_');
const assignee = slackUserId ? ('<@' + slackUserId + '>') : (ev.assignedUserName || '_Unassigned_');
const text = meta.emoji + ' ' + meta.title + ': ' + ev.name;

const blocks = [
  { type: 'header', text: { type: 'plain_text', text: meta.emoji + ' ' + meta.title, emoji: true } },
  { type: 'section', fields: [
    { type: 'mrkdwn', text: '*Task:*\n' + ev.name },
    { type: 'mrkdwn', text: '*Status:*\n' + (ev.status || meta.title) },
    { type: 'mrkdwn', text: '*Priority:*\n' + pe + ' ' + ev.priority },
    { type: 'mrkdwn', text: '*Due:*\n' + due }
  ]},
  { type: 'section', fields: [
    { type: 'mrkdwn', text: '*Assigned To:*\n' + assignee },
    { type: 'mrkdwn', text: '*Related:*\n' + related }
  ]},
  { type: 'actions', elements: [
    { type: 'button', text: { type: 'plain_text', text: '✅ Acknowledge', emoji: true }, style: 'primary', action_id: 'task_acknowledge', value: JSON.stringify({ taskId: ev.taskId, assignedUserId: ev.assignedUserId }) },
    { type: 'button', text: { type: 'plain_text', text: '🔗 Open in CRM', emoji: true }, url: 'https://rrespocrm-rsg-u69864.vm.elestio.app/#Task/view/' + ev.taskId }
  ]}
];
return [{ json: { channel: channel, text: text, blocks: blocks, taskId: ev.taskId, assignedUserId: ev.assignedUserId } }];
